// Claude Code Gate-0 capture hook (ADR-0032 §Gate-0, ADR-0033).
//
// One hidden `mage memory-hook` command, wired by `mage connect` into BOTH a
// PreToolUse and a PostToolUse group. With `autoMemoryDirectory` = the KB docs
// root, the agent's native-memory Write/Edit lands flat at the docs-root top; this
// hook intercepts those writes:
//   - a generated index (MEMORY.md / INDEX.md / _index.<wing>.md + reserved
//     scaffolding) → DENY (mage owns it; regenerated by `mage index`);
//   - a flat .md topic note → scrub (redact) + schema-map IN-FLIGHT and return it
//     as `updatedInput`, so it lands redacted + mage-shaped BEFORE it touches disk
//     (Gate-0); the PostToolUse arm then nudges the agent to `mage groom`;
//   - anything else (subdir, non-.md, a path outside the root) → PASS untouched.
//
// FAIL-OPEN, never DENY-on-error: any stdin/parse/fs/redact failure emits nothing
// and exits 0 — a capture hook that crashed or blocked would break the agent's
// writes. We emit JSON ONLY to deny a generated index or to rewrite a topic note;
// an unrelated write emits nothing, preserving the host's normal permission flow
// (an explicit `allow` there would bypass the user's own permission prompts).
// Mirrors the observe.ts / nudge.ts fail-open contract.

import { isAbsolute, relative } from "node:path";
import { Command } from "commander";
import { parseNote, stringifyNote } from "../../note.js";
import { resolveDocsRoot } from "../../paths.js";
import { redact } from "../../redact.js";
import { isGeneratedArtifact, scanNotes } from "../../scan.js";
import { type CcMemoryFrontmatter, mapCcMemoryToMageNote } from "./schema-map.js";

const DENY_REASON =
  "mage owns this index (regenerated by `mage index`). Write your lesson as a topic note at the KB root instead — mage scrubs it and re-indexes automatically.";

/** The pure decision for a PreToolUse Write/Edit — unit-testable, no stdout. */
export type MemoryDecision =
  | { kind: "deny"; reason: string }
  | {
      kind: "rewrite";
      updatedInput: Record<string, unknown>;
      reason: string;
      slug: string;
      masked: number;
    }
  | { kind: "pass" };

const PASS: MemoryDecision = { kind: "pass" };

// ─── narrowing helpers (mirror observe.ts / nudge.ts) ──────────────────────────

function obj(v: unknown): Record<string, unknown> | undefined {
  return v !== null && typeof v === "object" && !Array.isArray(v)
    ? (v as Record<string, unknown>)
    : undefined;
}

function str(v: unknown): string | undefined {
  return typeof v === "string" && v.length > 0 ? v : undefined;
}

/**
 * The docs-root-relative basename of a FLAT .md file written directly at the docs
 * root (a CC memory topic file), or null for a subdirectory write, a path that
 * escapes the root, or a non-.md file — all of which PASS untouched.
 */
function flatInboxRel(root: string, filePath: string): string | null {
  const rel = relative(root, filePath);
  if (!rel || rel.startsWith("..") || isAbsolute(rel)) return null; // outside the root
  if (rel.includes("/")) return null; // a subdirectory write, not a flat topic note
  if (!rel.endsWith(".md")) return null; // CC memory topic files are .md
  return rel;
}

/**
 * Best-guess the KB's primary wing (the modal wing across existing notes) so a
 * flat capture acquires the right tag at the source (ADR-0032 §2: "Gate-0
 * best-guess, groom confirms"). undefined on empty/error — the note then lands
 * cross-cutting and `mage groom` assigns the wing. Fail-open.
 */
async function bestGuessWing(root: string): Promise<string | undefined> {
  try {
    const counts = new Map<string, number>();
    for (const n of await scanNotes(root)) {
      for (const w of n.wings) counts.set(w.wing, (counts.get(w.wing) ?? 0) + 1);
    }
    let best: string | undefined;
    let bestN = 0;
    for (const [w, n] of counts) {
      if (n > bestN) {
        best = w;
        bestN = n;
      }
    }
    return best;
  } catch {
    return undefined;
  }
}

function rewriteReason(masked: number): string {
  return masked > 0
    ? `mage scrubbed ${masked} secret/PII value(s) and mapped this to its note schema.`
    : "mage mapped this to its note schema (no secrets found).";
}

// ─── pure decisions ────────────────────────────────────────────────────────────

/**
 * Decide what to do with a PreToolUse Write/Edit. Reads the filesystem only via
 * resolveDocsRoot/scanNotes (both fail-open); returns a {@link MemoryDecision}.
 */
export async function memoryPreToolUse(
  payload: Record<string, unknown>,
  opts: { cwd?: string } = {},
): Promise<MemoryDecision> {
  const toolName = str(payload.tool_name);
  if (toolName !== "Write" && toolName !== "Edit") return PASS;
  const input = obj(payload.tool_input);
  const filePath = input && str(input.file_path);
  if (!input || !filePath) return PASS;

  const cwd = opts.cwd ?? str(payload.cwd) ?? process.cwd();
  const resolved = await resolveDocsRoot(cwd).catch(() => null);
  if (!resolved) return PASS;

  const rel = flatInboxRel(resolved.root, filePath);
  if (rel === null) return PASS; // subdir / outside the root / non-.md → never touched

  // A generated index at the docs root → mage owns it (isGeneratedArtifact covers
  // MEMORY.md/INDEX.md/_index.*.md + IDENTITY/AGENTS/CLAUDE/Dashboard at the root).
  if (isGeneratedArtifact(rel)) return { kind: "deny", reason: DENY_REASON };

  // A flat topic note. Write carries the full file (schema-map + scrub); Edit
  // carries a fragment in new_string (scrub only — a schema-map needs a whole note).
  if (toolName === "Write") {
    const content = str(input.content);
    if (content === undefined) return PASS;
    const parsed = parseNote(content);
    const mapped = mapCcMemoryToMageNote(
      { frontmatter: parsed.frontmatter as unknown as CcMemoryFrontmatter, body: parsed.body },
      { wing: await bestGuessWing(resolved.root) },
    );
    const { text, findings } = redact(stringifyNote(mapped.frontmatter, mapped.body));
    return {
      kind: "rewrite",
      updatedInput: { ...input, content: text },
      reason: rewriteReason(findings.length),
      slug: mapped.slug,
      masked: findings.length,
    };
  }

  const newString = str(input.new_string);
  if (newString === undefined) return PASS;
  const { text, findings } = redact(newString);
  return {
    kind: "rewrite",
    updatedInput: { ...input, new_string: text },
    reason: rewriteReason(findings.length),
    slug: rel.replace(/\.md$/, ""),
    masked: findings.length,
  };
}

/**
 * The PostToolUse capture-nudge context for a topic-note write, or null. (No masked
 * count: redact() is idempotent, so re-scanning the scrubbed file yields 0 — the
 * count already rode the PreToolUse permissionDecisionReason the model saw.)
 */
export async function memoryPostToolUse(
  payload: Record<string, unknown>,
  opts: { cwd?: string } = {},
): Promise<string | null> {
  const toolName = str(payload.tool_name);
  if (toolName !== "Write" && toolName !== "Edit") return null;
  const input = obj(payload.tool_input);
  const filePath = input && str(input.file_path);
  if (!input || !filePath) return null;

  const cwd = opts.cwd ?? str(payload.cwd) ?? process.cwd();
  const resolved = await resolveDocsRoot(cwd).catch(() => null);
  if (!resolved) return null;

  const rel = flatInboxRel(resolved.root, filePath);
  if (rel === null || isGeneratedArtifact(rel)) return null;
  return `mage captured \`${rel.replace(/\.md$/, "")}\` — run \`mage groom\` to review and accept it into the knowledge base.`;
}

// ─── stdout emit (Claude Code hook JSON contracts) ─────────────────────────────

/** Emit a PreToolUse decision. PASS emits nothing (preserves the host's permission flow). */
export function emitPreToolUse(d: MemoryDecision): void {
  if (d.kind === "pass") return;
  const hookSpecificOutput: Record<string, unknown> = {
    hookEventName: "PreToolUse",
    permissionDecision: d.kind === "deny" ? "deny" : "allow",
    permissionDecisionReason: d.reason,
  };
  if (d.kind === "rewrite") hookSpecificOutput.updatedInput = d.updatedInput;
  process.stdout.write(`${JSON.stringify({ hookSpecificOutput })}\n`);
}

/** Emit a PostToolUse additionalContext nudge. */
export function emitPostToolUseContext(context: string): void {
  const out = { hookSpecificOutput: { hookEventName: "PostToolUse", additionalContext: context } };
  process.stdout.write(`${JSON.stringify(out)}\n`);
}

// ─── hook stdin (verbatim from nudge.ts / observe.ts fail-open contract) ────────

/** Drain stdin to a UTF-8 string; resolves "" on empty/closed/errored streams. */
function readStdinSafe(): Promise<string> {
  return new Promise<string>((resolve) => {
    const chunks: Buffer[] = [];
    process.stdin.on("data", (c: Buffer) => chunks.push(c));
    process.stdin.on("end", () => resolve(Buffer.concat(chunks).toString("utf8")));
    process.stdin.on("error", () => resolve(""));
  });
}

/** Parse stdin → a plain object, or null for invalid/array/primitive/null JSON. */
function parseHookPayload(raw: string): Record<string, unknown> | null {
  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch {
    return null;
  }
  if (parsed === null || typeof parsed !== "object" || Array.isArray(parsed)) return null;
  return parsed as Record<string, unknown>;
}

// ─── CLI registration (kept next to the handler) ───────────────────────────────

/**
 * Build the hidden `memory-hook` plumbing command. Reads the hook JSON on stdin,
 * dispatches on `hook_event_name`, and emits the deny/rewrite (PreToolUse) or
 * capture-nudge (PostToolUse) JSON. Wrapped fail-open: any error → silent exit 0,
 * so a capture gate never breaks the agent's tool calls.
 */
export function buildMemoryHookCommand(): Command {
  return new Command("memory-hook")
    .description(
      "Hook-fired Claude Code Gate-0 capture gate: on PreToolUse, redirect + scrub a native-memory write into mage's note schema (or deny a write to a generated index); on PostToolUse, nudge `mage groom` (ADR-0032/0033; never blocks the host)",
    )
    .option(
      "--cwd <dir>",
      "working directory used to locate the knowledge base (overrides the hook JSON cwd; defaults to it, then process.cwd())",
    )
    .action(async (opts: { cwd?: string }) => {
      try {
        const raw = await readStdinSafe();
        const payload = raw.trim().length === 0 ? null : parseHookPayload(raw);
        if (!payload) return;
        const event = str(payload.hook_event_name);
        if (event === "PreToolUse") {
          emitPreToolUse(await memoryPreToolUse(payload, { cwd: opts.cwd }));
        } else if (event === "PostToolUse") {
          const ctx = await memoryPostToolUse(payload, { cwd: opts.cwd });
          if (ctx !== null) emitPostToolUseContext(ctx);
        }
      } catch {
        // Fail open: a capture gate must never break the agent's tool calls.
      }
    });
}
